"use strict";parserFactory.register("fanficus.com",()=>new FanficusParser);class FanficusParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.querySelector(".ff-chapters-body");return util.hyperlinksToChapterList(e)}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(t){return t.querySelector("h1")}async fetchChapter(t){let e="https://fanficus-server-mirror-879c30cd977f.herokuapp.com/api/v1"+new URL(t).pathname,r=await HttpClient.fetchJson(e);return this.jsonToHtml(r.json)}jsonToHtml(t){let e=Parser.makeEmptyDocForContent(),r=e.dom.createElement("h1");r.textContent=t.value.title,e.content.appendChild(r);let n=util.sanitize("<div id='start'>"+t.value.text+"</div>");return e.content.appendChild(n.querySelector("div#start")),e.dom}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("app-post-main-info")]}}